namespace :backup do
  desc "Generate a backup archive"
  task generate: [:environment] do
    name = ENV['NAME']
    path = ENV['PATH']

    if name && path
      exec("tar -czf #{path}/#{name}.tgz #{Rails.root}")
    else
      puts "Please provide both NAME and PATH arguments."
    end
  end
end